  ('aboriginal-f0899a01-moex-00079', 'aboriginal-f0899a01', 'aboriginal-f0899a01-moex-114-d1a761c9', 'sub-aboriginal-f0899a01-03', NULL, 'single_choice', '關於國家賠償之敘述，下列何者正確？', '["國家賠償請求權，自請求權人知有損害時起，因2年間不行使而消滅", "國家賠償以回復原狀為原則", "外國人一律不得請求國家賠償", "國家賠償訴訟應適用行政訴訟法"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:37:31+00:00", "source_pdf_sha1": "a620b6990aa3", "answer_pdf_sha1": "42723ac4e3be", "source_family": "moex-gov-tw", "moex": {"exam_code": "114140", "c": "608", "s": "0603", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "行政法概要", "year": "114", "exam_name": "114年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": 48, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "法警"}'::jsonb, NULL),
  ('aboriginal-f0899a01-moex-00080', 'aboriginal-f0899a01', 'aboriginal-f0899a01-moex-114-d1a761c9', 'sub-aboriginal-f0899a01-03', NULL, 'single_choice', '就國家賠償之金額，賠償義務機關得於一定金額限度內逕行決定。該金額之限度，於中央機關由下列 何者定之？', '["內政部", "行政院", "法務部", "行政院主計總處"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:37:31+00:00", "source_pdf_sha1": "a620b6990aa3", "answer_pdf_sha1": "42723ac4e3be", "source_family": "moex-gov-tw", "moex": {"exam_code": "114140", "c": "608", "s": "0603", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "行政法概要", "year": "114", "exam_name": "114年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": 49, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "法警"}'::jsonb, NULL),
  ('aboriginal-f0899a01-moex-00081', 'aboriginal-f0899a01', 'aboriginal-f0899a01-moex-114-d1a761c9', 'sub-aboriginal-f0899a01-03', NULL, 'single_choice', '依目前最高行政法院見解，關於國家補償之敘述，下列何者錯誤？', '["即使係適法行使公權力，但已致特定人民之財產權發生特別犧牲，國家亦應有補償該人民之義務", "土地徵收未依限給予人民補償者，該徵收處分失其效力", "對於行政機關所為土地徵收補償爭議，行政法院得予以審查", "徵收前協議價購之性質，屬於私法上之土地買賣行為，與補償無關"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:37:31+00:00", "source_pdf_sha1": "a620b6990aa3", "answer_pdf_sha1": "42723ac4e3be", "source_family": "moex-gov-tw", "moex": {"exam_code": "114140", "c": "608", "s": "0603", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "行政法概要", "year": "114", "exam_name": "114年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": 50, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "法警"}'::jsonb, NULL),
  ('aboriginal-f0899a01-moex-00082', 'aboriginal-f0899a01', 'aboriginal-f0899a01-moex-113-06dee816', 'sub-aboriginal-f0899a01-01', NULL, 'essay', '甲具狀向地檢署誣告乙違犯竊盜罪，一個月後甲於檢察官偵訊時，經具
結後，甲指證歷歷親眼看見乙從被害人家中取走財物。試問，甲之行為
應如何論罪？（25 分）', '[]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:37:31+00:00", "source_pdf_sha1": "8b6008d70ff4", "answer_pdf_sha1": null, "source_family": "moex-gov-tw", "moex": {"exam_code": "113140", "c": "507", "s": "0805", "q": "1"}, "raw_section_label": "甲、申論題部分", "subject": "刑法與刑事訴訟法概要", "year": "113", "exam_name": "113年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": "一", "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "法警"}'::jsonb, NULL),
  ('aboriginal-f0899a01-moex-00083', 'aboriginal-f0899a01', 'aboriginal-f0899a01-moex-113-06dee816', 'sub-aboriginal-f0899a01-01', NULL, 'essay', '甲與鄰居乙素有糾紛，一日雙方吵架後，甲見乙之配偶丙站在家中窗內
察看，遂故意拿起石頭朝乙家中窗戶丟擲，該石頭打破乙家中窗戶後，
同時又砸傷丙。丙遂對甲提起傷害罪告訴，檢察官隨後也以甲涉犯傷害
罪提起公訴，並經一審法院判決有罪。甲上訴至二審法院審理時，乙始
向檢察官提起甲毀損家中窗戶之合法告訴，檢察官因而向二審法院表示
欲追加起訴甲涉犯毀損罪之部分。檢察官之追加起訴是否合法？（25 分）', '[]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:37:31+00:00", "source_pdf_sha1": "8b6008d70ff4", "answer_pdf_sha1": null, "source_family": "moex-gov-tw", "moex": {"exam_code": "113140", "c": "507", "s": "0805", "q": "1"}, "raw_section_label": "甲、申論題部分", "subject": "刑法與刑事訴訟法概要", "year": "113", "exam_name": "113年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": "二", "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "法警"}'::jsonb, NULL),
  ('aboriginal-f0899a01-moex-00084', 'aboriginal-f0899a01', 'aboriginal-f0899a01-moex-113-06dee816', 'sub-aboriginal-f0899a01-01', NULL, 'single_choice', '關於依照我國緩刑之相關規定，下列何者情形法院得宣告緩刑？', '["甲因犯刑法第320條第1項竊盜罪受有期徒刑2年6月之宣告", "甲因犯刑法第271條第1項殺人罪受無期徒刑之宣告", "甲前因犯刑法第271條第1項殺人罪受有期徒刑宣告，服刑完畢後經6年，又為刑法第221條 第1項強制性交行為後自首而受追訴", "甲前因犯刑法第271條第1項殺人罪受有期徒刑宣告，服刑完畢後經4年，又為刑法第221條 第1項強制性交行為後自首而受追訴"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:37:31+00:00", "source_pdf_sha1": "8b6008d70ff4", "answer_pdf_sha1": "64295f7ceaaf", "source_family": "moex-gov-tw", "moex": {"exam_code": "113140", "c": "507", "s": "0805", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "刑法與刑事訴訟法概要", "year": "113", "exam_name": "113年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": 1, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "法警"}'::jsonb, NULL),
  ('aboriginal-f0899a01-moex-00085', 'aboriginal-f0899a01', 'aboriginal-f0899a01-moex-113-06dee816', 'sub-aboriginal-f0899a01-01', NULL, 'single_choice', '下列何種情形非我國刑法上所規定的性交行為？', '["甲以陰莖插入乙之陰道", "甲以陰莖插入乙之肛門", "甲以手指插入乙之肛門", "甲以情趣用品插入乙之口腔"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:37:31+00:00", "source_pdf_sha1": "8b6008d70ff4", "answer_pdf_sha1": "64295f7ceaaf", "source_family": "moex-gov-tw", "moex": {"exam_code": "113140", "c": "507", "s": "0805", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "刑法與刑事訴訟法概要", "year": "113", "exam_name": "113年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": 2, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "法警"}'::jsonb, NULL),
  ('aboriginal-f0899a01-moex-00086', 'aboriginal-f0899a01', 'aboriginal-f0899a01-moex-113-06dee816', 'sub-aboriginal-f0899a01-01', NULL, 'single_choice', '救護車在執行職務時，開閃燈及鳴笛，但闖越紅燈而撞上綠燈通行的車輛，近來的法院判決多認 為救護車駕駛人不用負刑事責任。這類判決是基於那一種法律上的理由？', '["自助行為", "容許信賴", "得被害人承諾", "依職務上命令之行為"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:37:31+00:00", "source_pdf_sha1": "8b6008d70ff4", "answer_pdf_sha1": "64295f7ceaaf", "source_family": "moex-gov-tw", "moex": {"exam_code": "113140", "c": "507", "s": "0805", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "刑法與刑事訴訟法概要", "year": "113", "exam_name": "113年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": 3, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "法警"}'::jsonb, NULL)
